python3 -c "
from pyfoma import FST
g=FST.from_fomastring(open('test.foma').read())
rows=[]
with open('data/aka.trn') as f:
    for line in f:
        line=line.rstrip('\n')
        if not line: continue
        rows.append(line.split('\t'))
def inp(l,ft):
    return ''.join('[%s]'%t for t in ft.split(';'))+l
def outp(w,ft):
    return ''.join('[%s]'%t for t in ft.split(';'))+w
bad=0; ex=[]
for l,w,ft in rows:
    outs=set(g.generate(inp(l,ft)))
    exp=outp(w,ft)
    if outs!={exp}:
        bad+=1
        if len(ex)<10: ex.append((inp(l,ft),exp,outs))
print('errors',bad,'of',len(rows))
for e in ex: print(e)
"
